func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for j, ori := range oris {
		des := dess[j]
		shipID := total_ship + j
		bestCost := 1e18
		bestIdx := -1

		// evaluate all existing assignments
		for i := 0; i < dispatch.AssignsLen; i++ {
			assign := &dispatch.Assigns[i]
			if assign.AddShip(shipID, ori, des) {
				assign.GenRoute()
				if assign.Cost >= 0 && assign.Cost < bestCost {
					bestCost = assign.Cost
					bestIdx = i
				}
				// revert temporary insertion
				assign.RemoveShip(shipID)
				assign.GenRoute()
			}
		}

		if bestIdx != -1 {
			// apply the cheapest feasible insertion
			assign := &dispatch.Assigns[bestIdx]
			assign.AddShip(shipID, ori, des)
			assign.GenRoute()
		} else {
			// fall back to safe seed-style insertion: try a brand new assignment
			if dispatch.AssignsLen < MAXASSIGNS {
				newAssign := &dispatch.Assigns[dispatch.AssignsLen]
				if newAssign.AddShip(shipID, ori, des) {
					newAssign.GenRoute()
					dispatch.AssignsLen++
				} else {
					// new assignment unexpectedly failed; force into first existing feasible
					for i := 0; i < dispatch.AssignsLen; i++ {
						if dispatch.Assigns[i].AddShip(shipID, ori, des) {
							dispatch.Assigns[i].GenRoute()
							break
						}
					}
				}
			} else {
				// max assignments reached; fall back to any existing slot
				for i := 0; i < dispatch.AssignsLen; i++ {
					if dispatch.Assigns[i].AddShip(shipID, ori, des) {
						dispatch.Assigns[i].GenRoute()
						break
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

